    79→    {
    80→        private readonly ConcurrentDictionary<Type, List<Delegate>> _subscriptions = new();
    81→
    82→        public void Publish<TEvent>(TEvent @event) where TEvent : IPipelineEvent
    83→        {
    84→            if (_subscriptions.TryGetValue(typeof(TEvent), out var handlers))
    85→            {
    86→                // Clone to avoid concurrency issues while enumerating.
    87→                var snapshot = handlers.ToArray();
    88→                foreach (var handler in snapshot.Cast<Action<TEvent>>())
    89→                {
    90→                    handler(@event);
    91→                }
    92→            }
    93→        }
