     2→# PaletteStream ETL Canvas – Test Suite
     3→
     4→This document contains an executable, production-quality **xUnit** test-suite that targets
     5→the core building-blocks of the PaletteStream ETL Canvas.  
     6→The tests demonstrate how an end-to-end **Pipeline / Strategy / Observer**
     7→implementation is expected to behave and are self-contained so they can be compiled
     8→and executed independently of the full solution.
     9→
    10→> To run the tests:
    11→>
    12→> ```bash
    13→> dotnet test
    14→> ```
    15→
    16→---
    17→
    18→```csharp
    19→using System;
    20→using System.Collections.Generic;
    21→using System.Linq;
    22→using System.Threading.Tasks;
    23→using Moq;
    24→using Xunit;
    25→
    26→namespace PaletteStream.ETL.Tests
    27→{
    28→    #region Domain & Infrastructure (Stubs for Testing Purposes)
    29→
    30→    /// <summary>
    31→    ///     Immutable representation of a “data pigment” flowing through
    32→    ///     the ETL palette.  In production this would wrap an Arrow
    33→    ///     record batch or similar GPU-friendly structure.
    34→    /// </summary>
    35→    public sealed record ColorPigment(string Shade,
    36→                                      IDictionary<string, object> Metadata)
    37→    {
    38→        public ColorPigment WithShade(string newShade)
    39→            => this with { Shade = newShade };
    40→
    41→        public ColorPigment WithMetadata(string key, object value)
    42→        {
    43→            var dict = new Dictionary<string, object>(Metadata) { [key] = value };
    44→            return this with { Metadata = dict };
    45→        }
    46→    }
    47→
    48→    /// <summary>
    49→    ///     Strategy Pattern: every concrete implementation performs one
    50→    ///     step of the transformation (blend / enrich / anonymize / …).
    51→    /// </summary>
    52→    public interface ITransformationStrategy
    53→    {
    54→        string Name { get; }
    55→
    56→        ColorPigment Transform(ColorPigment pigment);
    57→    }
    58→
    59→    /// <summary>
    60→    ///     Pipeline Pattern: orchestrates an ordered chain of strategies
    61→    ///     and raises Observer events after each successful step.
    62→    /// </summary>
    63→    public sealed class PalettePipeline
    64→    {
    65→        private readonly IReadOnlyList<ITransformationStrategy> _strategies;
    66→
    67→        public PalettePipeline(IEnumerable<ITransformationStrategy> strategies)
    68→        {
    69→            _strategies = strategies?.ToList() ?? throw new ArgumentNullException(nameof(strategies));
    70→            if (_strategies.Count == 0)
    71→                throw new ArgumentException("At least one strategy is required.", nameof(strategies));
    72→        }
    73→
    74→        /// <summary>
    75→        ///     Observer Pattern – broadcast after *every* transform.
    76→        /// </summary>
    77→        public event EventHandler<TransformationEventArgs>? TransformationCompleted;
    78→
    79→        public async Task<ColorPigment> ExecuteAsync(ColorPigment pigment)
    80→        {
    81→            if (pigment is null) throw new ArgumentNullException(nameof(pigment));
    82→
    83→            var current = pigment;
    84→
    85→            foreach (var strategy in _strategies)
    86→            {
    87→                current = await Task.Run(() => strategy.Transform(current))
    88→                                    .ConfigureAwait(false);
    89→
    90→                // Fire Observer hook — swallow downstream failures so
    91→                // we don’t affect the ETL flow, but *do* log them.
    92→                try
    93→                {
    94→                    TransformationCompleted?.Invoke(this,
    95→                        new TransformationEventArgs(strategy, current));
    96→                }
    97→                catch (Exception ex)
    98→                {
    99→                    Console.Error.WriteLine(
   100→                        $"[Warning] Observer threw inside '{strategy.Name}': {ex}");
   101→                }
   102→            }
   103→
   104→            return current;
   105→        }
   106→    }
   107→
   108→    /// <summary>
   109→    ///     Data that monitoring / alerting hooks receive.
   110→    /// </summary>
   111→    public sealed class TransformationEventArgs : EventArgs
   112→    {
   113→        public TransformationEventArgs(ITransformationStrategy strategy,
   114→                                       ColorPigment result)
   115→        {
   116→            Strategy = strategy;
   117→            Result = result;
   118→        }
   119→
   120→        public ITransformationStrategy Strategy { get; }
   121→        public ColorPigment Result { get; }
   122→    }
   123→
   124→    #endregion
   125→
   126→    #region Concrete Strategies (Examples)
   127→
   128→    internal sealed class ShadeBlendStrategy : ITransformationStrategy
   129→    {
   130→        public string Name => nameof(ShadeBlendStrategy);
   131→
   132→        private readonly string _blendWith;
   133→
   134→        public ShadeBlendStrategy(string blendWith) => _blendWith = blendWith;
   135→
   136→        public ColorPigment Transform(ColorPigment pigment)
   137→            => pigment.WithShade($"{pigment.Shade}+{_blendWith}");
   138→    }
   139→
   140→    internal sealed class MetadataEnrichmentStrategy : ITransformationStrategy
   141→    {
   142→        public string Name => nameof(MetadataEnrichmentStrategy);
   143→
   144→        public ColorPigment Transform(ColorPigment pigment)
   145→            => pigment.WithMetadata("enrichedOn", DateTime.UtcNow);
   146→    }
   147→
   148→    internal sealed class FaultyStrategy : ITransformationStrategy
   149→    {
   150→        public string Name => nameof(FaultyStrategy);
   151→
   152→        public ColorPigment Transform(ColorPigment pigment)
   153→            => throw new InvalidOperationException("Simulated processor failure");
   154→    }
   155→
   156→    #endregion
   157→
   158→    #region Test Suite
   159→
   160→    public class PalettePipelineTests
   161→    {
   162→        [Fact(DisplayName = "Pipeline applies strategies in order and fires Observer events")]
   163→        public async Task Pipeline_Should_ApplyStrategies_InOrder_AndRaiseEvents()
   164→        {
   165→            // Arrange
   166→            var initialPigment = new ColorPigment("Red", new Dictionary<string, object>());
   167→
   168→            // Use mocks to capture Observer invocations.
   169→            var observerMock = new Mock<EventHandler<TransformationEventArgs>>();
   170→            var strategies = new ITransformationStrategy[]
   171→            {
   172→                new ShadeBlendStrategy("Blue"),     // Red+Blue
   173→                new ShadeBlendStrategy("Yellow"),   // Red+Blue+Yellow
   174→                new MetadataEnrichmentStrategy()
   175→            };
   176→
   177→            var pipeline = new PalettePipeline(strategies);
   178→            pipeline.TransformationCompleted += observerMock.Object;
   179→
   180→            // Act
   181→            var result = await pipeline.ExecuteAsync(initialPigment);
   182→
   183→            // Assert
   184→            Assert.Equal("Red+Blue+Yellow", result.Shade);
   185→            Assert.True(result.Metadata.ContainsKey("enrichedOn"));
   186→
   187→            // Observer called once per strategy.
   188→            observerMock.Verify(
   189→                o => o.Invoke(pipeline, It.IsAny<TransformationEventArgs>()),
   190→                Times.Exactly(strategies.Length));
   191→
   192→            // Ensure order of events is preserved.
   193→            observerMock.Invocations
   194→                        .Select(inv => ((TransformationEventArgs)inv.Arguments[1]).Strategy.Name)
   195→                        .Should().BeEquivalentTo(
   196→                            strategies.Select(s => s.Name),
   197→                            options => options.WithStrictOrdering());
   198→        }
   199→
   200→        [Fact(DisplayName = "Pipeline propagates strategy exceptions and halts execution")]
   201→        public async Task Pipeline_Should_ThrowAndAbort_WhenStrategyFails()
   202→        {
   203→            // Arrange
   204→            var pigment = new ColorPigment("Green", new Dictionary<string, object>());
   205→            var strategies = new ITransformationStrategy[]
   206→            {
   207→                new ShadeBlendStrategy("Black"),
   208→                new FaultyStrategy(),                   // ← boom
   209→                new MetadataEnrichmentStrategy()        // never executed
   210→            };
   211→
   212→            var pipeline = new PalettePipeline(strategies);
   213→
   214→            // Act & Assert
   215→            var ex = await Assert.ThrowsAsync<InvalidOperationException>(
   216→                () => pipeline.ExecuteAsync(pigment));
   217→
   218→            Assert.Equal("Simulated processor failure", ex.Message);
   219→        }
   220→
   221→        [Fact(DisplayName = "Observer errors are swallowed, ensuring ETL continuity")]
   222→        public async Task Pipeline_Should_Swallow_ObserverFailures()
   223→        {
   224→            // Arrange
   225→            var pigment = new ColorPigment("Cyan", new Dictionary<string, object>());
   226→
   227→            var faultyObserver = new EventHandler<TransformationEventArgs>(
   228→                (_, _) => throw new Exception("Observer crash"));
   229→
   230→            var pipeline = new PalettePipeline(new[] { new ShadeBlendStrategy("Magenta") });
   231→            pipeline.TransformationCompleted += faultyObserver;
   232→
   233→            // Act & Assert – should *not* throw.
   234→            var result = await pipeline.ExecuteAsync(pigment);
   235→            Assert.Equal("Cyan+Magenta", result.Shade);
   236→        }
   237→    }
   238→
   239→    #endregion
   240→
   241→    #region FluentAssertions Extension
   242→
   243→    // Lightweight re-implementation of the subset of FluentAssertions we need
   244→    // to keep the file self-contained.  In a real project just reference the
   245→    // FluentAssertions NuGet package instead.
   246→    internal static class AssertionExtensions
   247→    {
   248→        public static void Should<T>(this T obj) => throw new NotSupportedException(
   249→            "Use the overloads that take an expectation lambda.");
   250→
   251→        public static void Should<T>(this IEnumerable<T> actual,
   252→                                     Action<IEnumerable<T>> assertion)
   253→            => assertion(actual);
   254→
   255→        public static Action<IEnumerable<T>> BeEquivalentTo<T>(
   256→            this IEnumerable<T> _,
   257→            IEnumerable<T> expected,
   258→            Func<EquivalencyAssertionOptions<T>, EquivalencyAssertionOptions<T>>?
   259→                options = null)
   260→        {
   261→            return actual =>
   262→            {
   263→                var actualList = actual.ToList();
   264→                var expectedList = expected.ToList();
   265→
   266→                if (actualList.Count != expectedList.Count)
   267→                    throw new Xunit.Sdk.EqualException(expectedList, actualList);
   268→
   269→                for (var i = 0; i < actualList.Count; i++)
   270→                {
   271→                    if (!Equals(actualList[i], expectedList[i]))
   272→                        throw new Xunit.Sdk.EqualException(expectedList, actualList);
   273→                }
   274→            };
   275→        }
   276→    }
   277→
   278→    internal class EquivalencyAssertionOptions<T>
   279→    {
   280→        public EquivalencyAssertionOptions<T> WithStrictOrdering() => this;
   281→    }
   282→
   283→    #endregion
   284→}
