   102→    /// <summary>
   103→    /// Highly simplified pipeline that applies a chain of strategies
   104→    /// and notifies any registered observer.
   105→    /// </summary>
   106→    internal sealed class EtlPipeline
   107→    {
   108→        private readonly IEnumerable<ITransformationStrategy> _strategies;
   109→        private readonly IEnumerable<ITransformationObserver> _observers;
   110→
   111→        public EtlPipeline(IEnumerable<ITransformationStrategy> strategies,
   112→                           IEnumerable<ITransformationObserver>? observers = null)
   113→        {
   114→            _strategies = strategies ?? throw new ArgumentNullException(nameof(strategies));
   115→            _observers = observers ?? Array.Empty<ITransformationObserver>();
   116→        }
   117→
   118→        public DataPigment Execute(DataPigment pigment)
   119→        {
   120→            DataPigment current = pigment ?? throw new ArgumentNullException(nameof(pigment));
   121→
   122→            foreach (var strategy in _strategies)
   123→            {
   124→                try
   125→                {
   126→                    current = strategy.Execute(current);
   127→                    NotifyTransformed(current, strategy);
   128→                }
   129→                catch (Exception ex)
   130→                {
   131→                    NotifyError(current, ex);
   132→                    throw new PipelineException(
   133→                        $"Pipeline halted at '{strategy.GetType().Name}'.", ex);
   134→                }
   135→            }
   136→
   137→            return current;
   138→        }
