   140→        public Task<DataPigment> ExecuteAsync(DataPigment pigment,
   141→                                              CancellationToken token = default)
   142→            => Task.Run(() => Execute(pigment), token); // simple async wrapper
   143→
   144→        private void NotifyTransformed(DataPigment pigment, ITransformationStrategy strategy)
   145→        {
   146→            foreach (var obs in _observers)
   147→                obs.OnTransformed(pigment, strategy);
   148→        }
   149→
   150→        private void NotifyError(DataPigment pigment, Exception ex)
   151→        {
   152→            foreach (var obs in _observers)
   153→                obs.OnError(pigment, ex);
   154→        }
   155→    }
