    71→        private readonly IProducer<string, TValue> _producer;
    72→        private readonly ILogger _logger;
    73→        private readonly JsonSerializerOptions _serializerOptions;
    74→
    75→        public KafkaProducer(
    76→            KafkaProducerConfig config,
    77→            ILogger<KafkaProducer<TValue>> logger)
