    83→                DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull,
    84→                PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
    85→                WriteIndented = false
    86→            };
    87→
    88→            _producer = BuildProducer(config);
    89→            _logger.LogInformation(
    90→                "Kafka producer for {Type} initialised with bootstrap servers {BootstrapServers}.",
    91→                typeof(TValue).Name,
    92→                config.BootstrapServers);
    93→        }
    94→
    95→        private IProducer<string, TValue> BuildProducer(KafkaProducerConfig options)
    96→        {
    97→            var producerConfig = new ProducerConfig
    98→            {
    99→                BootstrapServers = options.BootstrapServers,
   100→                ClientId         = options.ClientId,
   101→                Acks             = Acks.All,
   102→                LingerMs         = options.LingerMs,
   103→                CompressionType  = options.CompressionType,
   104→                MessageSendMaxRetries = options.RetryCount,
   105→                EnableIdempotence = true, // Safe-produce mode
   106→                EnableDeliveryReports = true
   107→            };
   108→
   109→            return new ProducerBuilder<string, TValue>(producerConfig)
   110→                .SetValueSerializer(new JsonAsyncSerializer<TValue>(_serializerOptions))
   111→                .SetErrorHandler((_, e) =>
   112→                {
   113→                    // Centralised error handler to ensure we never silently swallow exceptions
   114→                    _logger.LogError(
   115→                        "Kafka producer error: {Reason} (IsFatal: {IsFatal})",
   116→                        e.Reason,
   117→                        e.IsFatal);
   118→                })
   119→                .Build();
   120→        }
