   122→        public async ValueTask ProduceAsync(
   123→            string topic,
   124→            string key,
   125→            TValue value,
   126→            CancellationToken cancellationToken = default)
   127→        {
   128→            if (string.IsNullOrWhiteSpace(topic))
   129→                throw new ArgumentException("Topic cannot be null or whitespace.", nameof(topic));
   130→
   131→            // Trace the produce operation for distributed observability
   132→            using var activity = ActivitySource.StartActivity(
   133→                "kafka.produce",
   134→                ActivityKind.Producer);
   135→
   136→            var message = new Message<string, TValue>
   137→            {
   138→                Key   = key,
   139→                Value = value,
   140→            };
   141→
   142→            // Embed trace context into Kafka headers for downstream correlation
   143→            if (activity?.Context.TraceId != default)
   144→            {
   145→                var traceParent = $"00-{activity.Context.TraceId}-{activity.Context.SpanId}-01";
   146→                message.Headers ??= new Headers();
   147→                message.Headers.Add("traceparent", Encoding.UTF8.GetBytes(traceParent));
   148→            }
   149→
   150→            try
   151→            {
   152→                var result = await _producer
   153→                    .ProduceAsync(topic, message, cancellationToken)
   154→                    .ConfigureAwait(false);
   155→
   156→                _logger.LogInformation(
   157→                    "Message produced to {TopicPartitionOffset} (latency {LatencyMs} ms).",
   158→                    result.TopicPartitionOffset,
   159→                    result.Status == PersistenceStatus.Persisted
   160→                        ? (int?)result.Timestamp.UtcDateTime.Subtract(DateTime.UtcNow).TotalMilliseconds * -1
   161→                        : null);
   162→            }
   163→            catch (ProduceException<string, TValue> ex) when (!ex.Error.IsFatal)
   164→            {
   165→                // Non-fatal errors can be retried/requeued depending on calling context
   166→                _logger.LogWarning(
   167→                    ex,
   168→                    "Non-fatal produce error to topic {Topic}: {Reason}",
   169→                    topic,
   170→                    ex.Error.Reason);
   171→                throw;
   172→            }
   173→            catch (ProduceException<string, TValue> ex)
   174→            {
   175→                _logger.LogError(
   176→                    ex,
   177→                    "Fatal produce error to topic {Topic}: {Reason}",
   178→                    topic,
   179→                    ex.Error.Reason);
   180→                throw;
   181→            }
   182→            catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
   183→            {
   184→                _logger.LogInformation(
   185→                    "Produce operation to topic {Topic} was canceled.",
   186→                    topic);
   187→                throw;
   188→            }
   189→        }
