    23→using System;
    24→using System.Collections.Generic;
    25→using System.Diagnostics;
    26→using System.Threading;
    27→using System.Threading.Tasks;
    28→using Microsoft.Extensions.Hosting;
    29→using Microsoft.Extensions.Logging;
    30→using System.Threading.Channels;
    31→
    32→namespace PaletteStream.Transformer.Core
    33→{
    34→    /// <summary>
    35→    /// Represents the background service responsible for orchestrating the
    36→    /// end-to-end data transformation lifecycle.
    37→    /// </summary>
    38→    public sealed class TransformationWorker : BackgroundService
    39→    {
    40→        private readonly ILogger<TransformationWorker> _logger;
    41→        private readonly ITransformationSource _source;
    42→        private readonly ITransformationSink _sink;
    43→        private readonly ITransformationStrategyFactory _strategyFactory;
    44→        private readonly IReadOnlyCollection<ITransformationObserver> _observers;
    45→        private readonly IDataQualityService _dataQualityService;
    46→
    47→        public TransformationWorker(
    48→            ILogger<TransformationWorker> logger,
    49→            ITransformationSource source,
    50→            ITransformationSink sink,
    51→            ITransformationStrategyFactory strategyFactory,
    52→            IEnumerable<ITransformationObserver> observers,
    53→            IDataQualityService dataQualityService)
    54→        {
    55→            _logger             = logger ?? throw new ArgumentNullException(nameof(logger));
    56→            _source             = source ?? throw new ArgumentNullException(nameof(source));
    57→            _sink               = sink ?? throw new ArgumentNullException(nameof(sink));
    58→            _strategyFactory    = strategyFactory ?? throw new ArgumentNullException(nameof(strategyFactory));
    59→            _dataQualityService = dataQualityService ?? throw new ArgumentNullException(nameof(dataQualityService));
    60→            _observers          = observers is IReadOnlyCollection<ITransformationObserver> list 
    61→                                      ? list
    62→                                      : new List<ITransformationObserver>(observers ?? Array.Empty<ITransformationObserver>());
    63→        }
    64→
    65→        /// <inheritdoc/>
    66→        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    67→        {
    68→            _logger.LogInformation("TransformationWorker started");
    69→
    70→            await foreach (var envelope in _source.ReadAsync(stoppingToken))
    71→            {
    72→                if (stoppingToken.IsCancellationRequested) break;
    73→
    74→                var stopwatch = Stopwatch.StartNew();
    75→
    76→                try
    77→                {
    78→                    await BroadcastAsync(o => o.OnTransformationStartedAsync(envelope, stoppingToken), stoppingToken);
    79→
    80→                    // Resolve and execute strategy
    81→                    var strat = _strategyFactory.Resolve(envelope.Metadata.TransformationType);
    82→                    var transformed = await strat.TransformAsync(envelope.Payload, stoppingToken);
    83→
    84→                    // Validate data-quality checkpoints
    85→                    var dqResult = _dataQualityService.Validate(transformed);
    86→
    87→                    if (!dqResult.IsSuccess)
    88→                    {
    89→                        await HandleDataQualityFailureAsync(envelope, dqResult, stoppingToken);
    90→                        continue; // skip normal output
    91→                    }
    92→
    93→                    await _sink.WriteAsync(transformed, envelope.Metadata, stoppingToken);
    94→
    95→                    stopwatch.Stop();
    96→                    _logger.LogInformation(
    97→                        "Successfully transformed envelope {EnvelopeId} in {ElapsedMs} ms",
    98→                        envelope.Metadata.EnvelopeId,
    99→                        stopwatch.ElapsedMilliseconds);
   100→
   101→                    await BroadcastAsync(o =>
   102→                        o.OnTransformationCompletedAsync(envelope, transformed, stoppingToken),
   103→                        stoppingToken);
   104→                }
   105→                catch (OperationCanceledException) when (stoppingToken.IsCancellationRequested)
   106→                {
   107→                    // Graceful shutdown
   108→                    _logger.LogInformation("Cancellation requested. Shutting transformation loop down.");
   109→                    break;
   110→                }
   111→                catch (Exception ex)
   112→                {
   113→                    await HandleUnhandledExceptionAsync(envelope, ex, stoppingToken);
   114→                }
   115→            }
   116→
   117→            _logger.LogInformation("TransformationWorker stopped");
   118→        }
   119→
   120→        #region Helper / Error Handling
   121→
   122→        private async Task HandleDataQualityFailureAsync(
   123→            TransformationEnvelope envelope,
   124→            DataQualityResult dqResult,
   125→            CancellationToken token)
   126→        {
   127→            _logger.LogWarning(
   128→                "DataQuality validation failed for envelope {EnvelopeId}: {Issues}",
   129→                envelope.Metadata.EnvelopeId,
   130→                string.Join(" | ", dqResult.Issues));
   131→
   132→            await _sink.PublishDeadLetterAsync(envelope, dqResult, token);
   133→
   134→            await BroadcastAsync(o =>
   135→                o.OnTransformationFailedAsync(
   136→                    envelope,
   137→                    new DataQualityException(dqResult.Issues),
   138→                    token),
   139→                token);
   140→        }
   141→
   142→        private async Task HandleUnhandledExceptionAsync(
   143→            TransformationEnvelope envelope,
   144→            Exception ex,
   145→            CancellationToken token)
   146→        {
   147→            _logger.LogError(ex,
   148→                "Unhandled exception while processing envelope {EnvelopeId}",
   149→                envelope.Metadata.EnvelopeId);
   150→
   151→            await _sink.PublishDeadLetterAsync(envelope, ex, token);
   152→
   153→            await BroadcastAsync(o => o.OnTransformationFailedAsync(envelope, ex, token), token);
   154→        }
   155→
   156→        private async Task BroadcastAsync(
   157→            Func<ITransformationObserver, Task> notify,
   158→            CancellationToken token)
   159→        {
   160→            foreach (var observer in _observers)
   161→            {
   162→                try
   163→                {
   164→                    if (token.IsCancellationRequested) return;
   165→                    await notify(observer);
   166→                }
   167→                catch (Exception ex)
   168→                {
   169→                    // Observers should never bring down the worker
   170→                    _logger.LogWarning(ex,
   171→                        "Observer {Observer} threw during notification. Continuing...",
   172→                        observer.GetType().Name);
   173→                }
   174→            }
   175→        }
   176→
   177→        #endregion
   178→    }
   179→
   180→    #region Contracts / Supporting Models
   181→
   182→    /// <summary>
   183→    /// Represents a source capable of streaming raw data envelopes.
   184→    /// </summary>
   185→    public interface ITransformationSource
   186→    {
   187→        IAsyncEnumerable<TransformationEnvelope> ReadAsync(CancellationToken token);
   188→    }
   189→
   190→    /// <summary>
   191→    /// Represents the downstream sink that stores curated data or dead-letter items.
   192→    /// </summary>
   193→    public interface ITransformationSink
   194→    {
   195→        Task WriteAsync(TransformedData data, TransformationMetadata metadata, CancellationToken token);
   196→
   197→        Task PublishDeadLetterAsync(
   198→            TransformationEnvelope envelope,
   199→            object error,
   200→            CancellationToken token);
   201→    }
   202→
   203→    /// <summary>
   204→    /// Factory responsible for resolving the correct transformation strategy.
   205→    /// </summary>
   206→    public interface ITransformationStrategyFactory
   207→    {
   208→        ITransformationStrategy Resolve(string transformationType);
   209→    }
   210→
   211→    /// <summary>
   212→    /// Strategy-pattern abstraction for performing a data transformation.
   213→    /// </summary>
   214→    public interface ITransformationStrategy
   215→    {
   216→        Task<TransformedData> TransformAsync(RawData data, CancellationToken token);
   217→    }
   218→
   219→    /// <summary>
   220→    /// Hook for observing lifecycle events emitted by <see cref="TransformationWorker"/>.
   221→    /// </summary>
   222→    public interface ITransformationObserver
   223→    {
   224→        Task OnTransformationStartedAsync(TransformationEnvelope envelope, CancellationToken token);
   225→
   226→        Task OnTransformationCompletedAsync(
   227→            TransformationEnvelope envelope,
   228→            TransformedData result,
   229→            CancellationToken token);
   230→
   231→        Task OnTransformationFailedAsync(
   232→            TransformationEnvelope envelope,
   233→            Exception ex,
   234→            CancellationToken token);
   235→    }
   236→
   237→    /// <summary>
   238→    /// Validates transformed data against data-quality rules.
   239→    /// </summary>
   240→    public interface IDataQualityService
   241→    {
   242→        DataQualityResult Validate(TransformedData data);
   243→    }
   244→
   245→    /// <summary>
   246→    /// Raw un-curated data (“pigment”) flowing in from an upstream source.
   247→    /// </summary>
   248→    public sealed record RawData
   249→    {
   250→        // In a real system this would wrap a DataFrame or a strongly-typed POCO collection.
   251→        public byte[] Buffer { get; init; } = Array.Empty<byte>();
   252→    }
   253→
   254→    /// <summary>
   255→    /// Curated, validated data ready for downstream zones.
   256→    /// </summary>
   257→    public sealed record TransformedData
   258→    {
   259→        // Again, this could be a Microsoft.Data.Analysis.DataFrame
   260→        public byte[] Buffer { get; init; } = Array.Empty<byte>();
   261→        public DateTime TransformedUtc { get; init; } = DateTime.UtcNow;
   262→    }
   263→
   264→    public sealed record TransformationMetadata
   265→    {
   266→        public Guid   EnvelopeId         { get; init; } = Guid.NewGuid();
   267→        public string TransformationType { get; init; } = string.Empty;
   268→        public DateTime ReceivedUtc      { get; init; } = DateTime.UtcNow;
   269→    }
   270→
   271→    /// <summary>
   272→    /// Combines raw data with the metadata required to perform a transformation.
   273→    /// </summary>
   274→    public sealed record TransformationEnvelope
   275→    {
   276→        public RawData               Payload  { get; init; } = new();
   277→        public TransformationMetadata Metadata { get; init; } = new();
   278→    }
   279→
   280→    /// <summary>
   281→    /// Result of a data-quality check pass/fail.
   282→    /// </summary>
   283→    public sealed record DataQualityResult
   284→    {
   285→        public bool                IsSuccess { get; init; } = true;
   286→        public IReadOnlyList<string> Issues   { get; init; } = Array.Empty<string>();
   287→
   288→        public static DataQualityResult Success() => new() { IsSuccess = true };
   289→        public static DataQualityResult Failure(IEnumerable<string> issues) =>
   290→            new()
   291→            {
   292→                IsSuccess = false,
   293→                Issues    = new List<string>(issues)
   294→            };
   295→    }
   296→
   297→    /// <summary>
   298→    /// Exception type used to surface data-quality errors.
   299→    /// </summary>
   300→    public sealed class DataQualityException : Exception
   301→    {
   302→        public IReadOnlyList<string> Issues { get; }
   303→
   304→        public DataQualityException(IEnumerable<string> issues)
   305→            : base($"Data quality validation failed: {string.Join(" | ", issues)}")
   306→        {
   307→            Issues = new List<string>(issues);
   308→        }
   309→    }
   310→
   311→    #endregion
   312→}
