    28→    /// <summary>
    29→    /// Contract for deserializing an incoming Kafka message payload into a CLR object.
    30→    /// </summary>
    31→    /// <typeparam name="TKey">Kafka message key.</typeparam>
    32→    /// <typeparam name="TValue">Kafka message value.</typeparam>
