    38→    /// <summary>
    39→    /// Marker interface for background consumers so that they can be registered as hosted services
    40→    /// or supervised by a service orchestrator.
    41→    /// </summary>
    42→    public interface IKafkaConsumer : IAsyncDisposable
    43→    {
    44→        Task StartAsync(CancellationToken ct = default);
    45→        Task StopAsync(CancellationToken ct = default);
