    48→    /// <summary>
    49→    /// A resilient Kafka consumer that encapsulates polling, error handling,
    50→    /// deserialization and commit logic.
    51→    /// </summary>
    52→    public sealed class KafkaConsumer<TKey, TValue> : IKafkaConsumer
    53→    {
    54→        private readonly IConsumer<TKey, byte[]> _innerConsumer;
    55→        private readonly IMessageDeserializer<TKey, TValue> _deserializer;
    56→        private readonly Func<TValue, Task> _handler;
    57→        private readonly ILogger<KafkaConsumer<TKey, TValue>> _logger;
    58→        private readonly IEnumerable<string> _topics;
    59→        private readonly bool _enableAutoCommit;
    60→        private readonly TimeSpan _pollTimeout = TimeSpan.FromMilliseconds(250);
    61→        private readonly BackoffStrategy _backoff = new();
    62→        private readonly CancellationTokenSource _internalCts = new();
    63→
    64→        private Task? _processingTask;
    65→
    66→        /// <summary>
    67→        /// Initializes a new instance of the <see cref="KafkaConsumer{TKey,TValue}"/> class.
    68→        /// </summary>
    69→        /// <param name="topics">The topics to subscribe to.</param>
    70→        /// <param name="consumer">Underlying Confluent consumer.</param>
    71→        /// <param name="deserializer">Deserializer implementation.</param>
    72→        /// <param name="handler">Delegate that processes messages.</param>
    73→        /// <param name="logger">Structured logger.</param>
    74→        /// <param name="enableAutoCommit">Indicates whether offsets are auto-committed.</param>
    75→        /// <exception cref="ArgumentNullException">Thrown when any dependency is null.</exception>
    76→        public KafkaConsumer(
    77→            IEnumerable<string> topics,
    78→            IConsumer<TKey, byte[]> consumer,
    79→            IMessageDeserializer<TKey, TValue> deserializer,
    80→            Func<TValue, Task> handler,
    81→            ILogger<KafkaConsumer<TKey, TValue>> logger,
    82→            bool enableAutoCommit = false)
    83→        {
    84→            _topics = topics ?? throw new ArgumentNullException(nameof(topics));
    85→            _innerConsumer = consumer ?? throw new ArgumentNullException(nameof(consumer));
    86→            _deserializer = deserializer ?? throw new ArgumentNullException(nameof(deserializer));
    87→            _handler = handler ?? throw new ArgumentNullException(nameof(handler));
    88→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    89→            _enableAutoCommit = enableAutoCommit;
    90→        }
    91→
    92→        #region IKafkaConsumer
    93→
    94→        public Task StartAsync(CancellationToken ct = default)
    95→        {
    96→            // Guard against multiple starts.
    97→            if (_processingTask != null)
    98→            {
    99→                throw new InvalidOperationException("Consumer already started.");
   100→            }
   101→
   102→            _logger.LogInformation("Starting Kafka consumer for topics: {Topics}", string.Join(", ", _topics));
   103→            _innerConsumer.Subscribe(_topics);
   104→
   105→            var linked = CancellationTokenSource.CreateLinkedTokenSource(ct, _internalCts.Token);
   106→            _processingTask = Task.Run(() => ConsumeLoopAsync(linked.Token), linked.Token);
   107→
   108→            return _processingTask.IsCompleted ? _processingTask : Task.CompletedTask;
   109→        }
   110→
   111→        public async Task StopAsync(CancellationToken ct = default)
   112→        {
   113→            if (_processingTask == null)
   114→            {
   115→                _logger.LogWarning("Stop requested but consumer was never started.");
   116→                return;
   117→            }
   118→
   119→            _internalCts.Cancel();
   120→
   121→            // Allow configured timeout for graceful drain.
   122→            if (_enableAutoCommit)
   123→            {
   124→                _logger.LogDebug("Committing offsets before shutdown.");
   125→                SafeCommit();
   126→            }
   127→
   128→            try
   129→            {
   130→                using var timeout = CancellationTokenSource.CreateLinkedTokenSource(ct);
   131→                timeout.CancelAfter(TimeSpan.FromSeconds(30));
   132→                await Task.WhenAny(_processingTask, Task.Delay(Timeout.Infinite, timeout.Token));
   133→            }
   134→            catch (OperationCanceledException)
   135→            {
   136→                _logger.LogWarning("Forced shutdown due to timeout.");
   137→            }
   138→            finally
   139→            {
   140→                _innerConsumer.Close();
   141→                _innerConsumer.Dispose();
   142→                _logger.LogInformation("Kafka consumer shutdown completed.");
   143→            }
   144→        }
   145→
   146→        public async ValueTask DisposeAsync()
   147→        {
   148→            await StopAsync();
   149→        }
   150→
   151→        #endregion
   152→
   153→        #region Core Loop
   154→
   155→        private async Task ConsumeLoopAsync(CancellationToken ct)
   156→        {
   157→            var sw = Stopwatch.StartNew();
   158→            while (!ct.IsCancellationRequested)
   159→            {
   160→                try
   161→                {
   162→                    var consumeResult = _innerConsumer.Consume(_pollTimeout);
   163→                    if (consumeResult == null) continue; // No message
   164→
   165→                    // Reset backoff counter on successful poll.
   166→                    _backoff.Reset();
   167→
   168→                    TValue payload;
   169→                    try
   170→                    {
   171→                        payload = _deserializer.Deserialize(consumeResult);
   172→                    }
   173→                    catch (Exception ex)
   174→                    {
   175→                        HandleDeserializationError(consumeResult, ex);
   176→                        continue; // skip to next message
   177→                    }
   178→
   179→                    // Process the message using the provided delegate.
   180→                    await _handler(payload);
   181→
   182→                    if (!_enableAutoCommit)
   183→                    {
   184→                        SafeCommit(consumeResult);
   185→                    }
   186→                }
   187→                catch (ConsumeException ce)
   188→                {
   189→                    _logger.LogError(ce, "Fatal error in Consume: {@Error}", ce.Error);
   190→                    await BackoffAsync(ct);
   191→                }
   192→                catch (OperationCanceledException) when (ct.IsCancellationRequested)
   193→                {
   194→                    // Graceful shutdown requested.
   195→                    _logger.LogInformation("Consumer cancellation requested; stopping.");
   196→                    break;
   197→                }
   198→                catch (Exception ex)
   199→                {
   200→                    _logger.LogError(ex, "Unhandled exception in Kafka consumer loop.");
   201→                    await BackoffAsync(ct);
   202→                }
   203→            }
   204→
   205→            sw.Stop();
   206→            _logger.LogInformation("Consumer loop exited after {Elapsed:g}.", sw.Elapsed);
   207→        }
   208→
   209→        #endregion
   210→
   211→        #region Helper Methods
   212→
   213→        private void HandleDeserializationError(ConsumeResult<TKey, byte[]> result, Exception ex)
   214→        {
   215→            // In production this may route the bad payload to a dead-letter queue.
   216→            _logger.LogError(ex,
   217→                "Failed to deserialize message from topic {Topic} at {Partition}:{Offset}. Skipping.",
   218→                result.Topic, result.Partition, result.Offset);
   219→        }
   220→
   221→        private void SafeCommit(ConsumeResult<TKey, byte[]>? result = null)
   222→        {
   223→            try
   224→            {
   225→                if (result == null)
   226→                {
   227→                    _innerConsumer.Commit();
   228→                }
   229→                else
   230→                {
   231→                    _innerConsumer.Commit(result);
   232→                }
   233→            }
   234→            catch (KafkaException ke)
   235→            {
   236→                _logger.LogWarning(ke, "Failed to commit offsets: {Reason}", ke.Error.Reason);
   237→            }
   238→        }
   239→
   240→        private async Task BackoffAsync(CancellationToken ct)
   241→        {
   242→            var delay = _backoff.Next();
   243→            _logger.LogWarning("Backing off for {Delay} after error.", delay);
   244→            try
   245→            {
   246→                await Task.Delay(delay, ct);
   247→            }
   248→            catch (OperationCanceledException)
   249→            {
   250→                // Swallow since shutdown requested.
   251→            }
   252→        }
   253→
   254→        #endregion
   255→
   256→        #region Nested Backoff Strategy
   257→
   258→        /// <summary>
   259→        /// Very small, self-contained exponential backoff implementation with jitter.
   260→        /// </summary>
   261→        private sealed class BackoffStrategy
   262→        {
   263→            private const int MaxExponent = 6; // 2^6 * Base = 64 * 250ms ≈ 16s
   264→            private readonly Random _rng = new();
   265→            private readonly TimeSpan _baseDelay = TimeSpan.FromMilliseconds(250);
   266→            private int _failureCount;
   267→
   268→            public TimeSpan Next()
   269→            {
   270→                var exponent = Math.Min(_failureCount++, MaxExponent);
   271→                var delay = TimeSpan.FromMilliseconds(_baseDelay.TotalMilliseconds * Math.Pow(2, exponent));
   272→
   273→                // Add jitter (+/- 15%).
   274→                var jitterPercentage = _rng.NextDouble() * 0.3 - 0.15;
   275→                var jitter = TimeSpan.FromMilliseconds(delay.TotalMilliseconds * jitterPercentage);
   276→                return delay + jitter;
   277→            }
   278→
   279→            public void Reset() => _failureCount = 0;
   280→        }
   281→
   282→        #endregion
   283→    }
   284→}
