   149→    internal sealed class TransformerEngine : ITransformerEngine
   150→    {
   151→        private readonly IEnumerable<ITransformationStrategy> _strategies;
   152→        private readonly IEnumerable<ITransformationObserver> _observers;
   153→        private readonly ILogger<TransformerEngine>           _logger;
   154→
   155→        public TransformerEngine(
   156→            IEnumerable<ITransformationStrategy> strategies,
   157→            IEnumerable<ITransformationObserver> observers,
   158→            ILogger<TransformerEngine> logger)
   159→        {
   160→            _strategies = strategies;
   161→            _observers  = observers;
   162→            _logger     = logger;
