   164→
   165→        public async Task<TransformationResult> TransformAsync(
   166→            TransformationContext context,
   167→            CancellationToken token = default)
   168→        {
   169→            _logger.LogDebug("Starting transformation for CorrelationId={CorrelationId}", context.Metadata.CorrelationId);
   170→            foreach (ITransformationObserver observer in _observers) observer.OnBeforeTransform(context);
   171→
   172→            TransformationPayload currentPayload = context.Payload;
   173→
   174→            foreach (ITransformationStrategy strategy in _strategies)
   175→            {
   176→                token.ThrowIfCancellationRequested();
   177→                currentPayload = await strategy.ApplyAsync(currentPayload, token);
   178→            }
   179→
   180→            var result = new TransformationResult(currentPayload, context.Metadata with { ProcessedUtc = DateTimeOffset.UtcNow });
   181→
   182→            foreach (ITransformationObserver observer in _observers) observer.OnAfterTransform(result);
   183→            _logger.LogDebug("Completed transformation for CorrelationId={CorrelationId}", context.Metadata.CorrelationId);
   184→
   185→            return result;
   186→        }
