   136→    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
   137→    {
   138→        _log.LogInformation("Quality worker starting with poll interval: {PollInterval} ms", _opts.PollIntervalMs);
   139→
   140→        while (!stoppingToken.IsCancellationRequested)
   141→        {
   142→            var sw = Stopwatch.StartNew();
   143→            try
   144→            {
   145→                await CheckZonesAsync(stoppingToken);
   146→            }
   147→            catch (Exception ex)
   148→            {
   149→                _log.LogError(ex, "Quality pass failed");
   150→            }
   151→            finally
   152→            {
   153→                sw.Stop();
   154→                _log.LogDebug("Quality pass completed in {ElapsedMs} ms", sw.ElapsedMilliseconds);
   155→            }
   156→
   157→            // Wait for next tick unless cancelled
   158→            try
   159→            {
   160→                await Task.Delay(_opts.PollIntervalMs, stoppingToken);
   161→            }
   162→            catch (TaskCanceledException)
   163→            {
   164→                // gracefully exit
   165→            }
   166→        }
   167→
   168→        _log.LogInformation("Quality worker stopping.");
   169→    }
   170→
   171→    private async Task CheckZonesAsync(CancellationToken ct)
   172→    {
   173→        var zones = _opts.Zones.Length == 0
   174→            ? await _lakeClient.ListZonesAsync(ct)
   175→            : _opts.Zones;
   176→
   177→        foreach (var zone in zones)
   178→        {
   179→            if (ct.IsCancellationRequested) break;
   180→
   181→            _log.LogInformation("Running quality checks on {Zone}", zone);
   182→
   183→            var datasets = await _lakeClient.ListDatasetsAsync(zone, ct);
   184→            if (!datasets.Any())
   185→            {
   186→                _log.LogWarning("No datasets discovered in zone {Zone}", zone);
   187→                continue;
   188→            }
   189→
   190→            var tasks = datasets.Select(ds => EvaluateDatasetAsync(zone, ds, ct));
   191→            await Task.WhenAll(tasks);
   192→        }
   193→    }
