   212→                issues.Add(new QualityIssue(QualitySeverity.Critical,
   213→                    $"Dataset contains {stats.DuplicateCount} duplicate records"));
   214→            }
   215→
   216→            // Publish result
   217→            var result = new QualityCheckResult(
   218→                Zone: zone,
   219→                Dataset: dataset,
   220→                TimestampUtc: DateTime.UtcNow,
   221→                IsSuccess: issues.Count == 0,
   222→                Issues: issues);
   223→
   224→            await _publisher.PublishAsync(result, ct);
   225→
   226→            if (issues.Count == 0)
   227→            {
   228→                _log.LogInformation("[{Zone}/{Dataset}] Quality OK", zone, dataset);
   229→            }
   230→            else
   231→            {
   232→                foreach (var issue in issues)
   233→                {
   234→                    _log.Log(issue.Severity == QualitySeverity.Critical ? LogLevel.Error : LogLevel.Warning,
   235→                        "[{Zone}/{Dataset}] {Severity} – {Description}",
   236→                        zone, dataset, issue.Severity, issue.Description);
   237→                }
   238→            }
   239→        }
   240→        catch (Exception ex)
   241→        {
   242→            _log.LogError(ex, "Failed to evaluate dataset {Zone}/{Dataset}", zone, dataset);
   243→        }
   244→    }
   245→}
