```csharp
public sealed class ClaimCheckConsumer : BackgroundService
{
    private readonly IDataLakeClient _dataLakeClient;
    private readonly QualityCheckRunner _qualityRunner;
    private readonly IKafkaConsumer _kafkaConsumer;
    private readonly ClaimCheckOptions _options;
    private readonly ILogger<ClaimCheckConsumer> _logger;

    public ClaimCheckConsumer(
        IDataLakeClient dataLakeClient,
        QualityCheckRunner qualityRunner,
        IKafkaConsumer kafkaConsumer,
        IOptions<ClaimCheckOptions> options,
        ILogger<ClaimCheckConsumer> logger)
    {
        _dataLakeClient = dataLakeClient;
        _qualityRunner = qualityRunner;
        _kafkaConsumer = kafkaConsumer;
        _options = options.Value;
        _logger = logger;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        await _kafkaConsumer.StartAsync(stoppingToken);

        // Consumer handler is set up during DI registration
        // See ProcessClaimCheckAsync for message handling
    }

    public async Task ProcessClaimCheckAsync(
        DataTransformedClaimCheckEvent claimCheck,
        CancellationToken ct)
    {
        _logger.LogInformation(
            "Processing claim check for {CorrelationId}, Data: {Zone}/{Path}",
            claimCheck.CorrelationId,
            claimCheck.DataStorageZone,
            claimCheck.DataBlobPath);

        try
        {
            // 1. Download data from blob storage
            await using var dataStream = await _dataLakeClient.DownloadAsync(
                claimCheck.DataStorageZone,
                claimCheck.DataBlobPath,
                ct);

            // 2. Verify checksum if enabled
            if (_options.VerifyChecksum && !string.IsNullOrEmpty(claimCheck.ChecksumSha256))
            {
                var actualChecksum = ComputeSha256(dataStream);
                if (actualChecksum != claimCheck.ChecksumSha256)
                {
                    throw new DataIntegrityException(
                        $"Checksum mismatch for {claimCheck.DataBlobPath}");
                }
                dataStream.Position = 0;
            }

            // 3. Deserialize data
            var records = await DeserializeAsync(dataStream, claimCheck.DataFormat, ct);

            // 4. Create DataBatch and run quality checks
            var batch = new DataBatch(
                Guid.Parse(claimCheck.CorrelationId ?? Guid.NewGuid().ToString()),
                new Dictionary<string, object>
                {
                    ["records"] = records,
                    ["source"] = claimCheck.DataBlobPath,
                    ["format"] = claimCheck.DataFormat
                });

            var summary = await _qualityRunner.RunAsync(batch, ct);

            _logger.LogInformation(
                "Quality check completed for {CorrelationId}. Failures: {HasFailures}",
                claimCheck.CorrelationId,
                summary.HasFailures);

            // 5. Optionally delete staging data after successful processing
            if (_options.DeleteAfterProcessing && !summary.HasFailures)
            {
                await _dataLakeClient.DeleteAsync(
                    claimCheck.DataStorageZone,
                    claimCheck.DataBlobPath,
                    ct);
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex,
                "Failed to process claim check for {CorrelationId}",
                claimCheck.CorrelationId);
            throw; // Will be handled by Kafka consumer (DLQ)
        }
    }

    private static string ComputeSha256(Stream stream)
    {
        using var sha256 = SHA256.Create();
        var hash = sha256.ComputeHash(stream);
        return Convert.ToBase64String(hash);
    }

    private static async Task<IReadOnlyCollection<object>> DeserializeAsync(
        Stream stream,
        string format,
        CancellationToken ct)
    {
        // Implementation varies by format
        return await JsonSerializer.DeserializeAsync<List<object>>(stream, cancellationToken: ct)
            ?? new List<object>();
    }
}
